    def countDigitOne(self, n: int) -> int:
        count = 0
        i = 1
        while i <= n:
            high = n // (i * 10)
            current = (n // i) % 10
            low = n % i
            if current > 1:
                count += (high + 1) * i
            elif current == 1:
                count += high * i + low + 1
            else:
                count += high * i
            i *= 10
